INSERT INTO FWK_PROPERTY ( PROPERTY_GROUP_ID, PROPERTY_ID, PROPERTY_NAME, PROPERTY_DESC, DATA_TYPE, VALID_DATA, DEFAULT_VALUE, LAST_UPDATE_USER_ID, LAST_UPDATE_DTIME ) SELECT A.* FROM (
SELECT #{propertyGroupId}, #{item.propertyId}, #{item.propertyName, jdbcType=VARCHAR}, #{item.propertyDesc, jdbcType=VARCHAR}, #{item.dataType, jdbcType=VARCHAR}, #{item.validData, jdbcType=VARCHAR}, #{item.defaultValue, jdbcType=VARCHAR}, #{lastUpdateUserId}, #{lastUpdateDtime} FROM DUAL
) A

mapper.delete:
